import json
from openai import OpenAI

client = OpenAI()

tools = [
    {
        'type': 'function',
        'function': {
            'name': 'web_search',
            'description': 'Search the web for current factual information.',
            'parameters': {
                'type': 'object',
                'properties': {
                    'query': {'type': 'string', 'description': 'Search query'},
                },
                'required': ['query'],
            },
        },
    }
]

def mock_search(query: str) -> str:
    # In production: call Bing, Tavily, or a vector DB
    return f'[Search results for: {query}] ... (retrieved passages here)'

def tool_grounded_query(question: str) -> str:
    messages = [{'role': 'user', 'content': question}]
    while True:
        resp = client.chat.completions.create(
            model='claude-sonnet-4-6',
            messages=messages,
            tools=tools,
            tool_choice='auto',
        )
        msg = resp.choices[0].message
        if msg.tool_calls:
            messages.append(msg)
            for tc in msg.tool_calls:
                args = json.loads(tc.function.arguments)
                result = mock_search(args['query'])
                messages.append({
                    'role': 'tool',
                    'tool_call_id': tc.id,
                    'content': result,
                })
        else:
            return msg.content
